Here is the JavaScript code that does what you asked for:

```javascript
// Loop through the child elements of the tbody element with id "target_table"
var items = document.getElementById("target_table").children;

// For each item element, get the value of the "data-sort" attribute in the 8th child
for (var i = 0; i < items.length; i++) {
  var item = items[i];
  var sortValue = item.children[7].getAttribute("data-sort");

  // Convert the sort value to a number and multiply it by 1000
  var sortDate = new Date(Number(sortValue) * 1000);

  // If the date of the new date object is more than 1 day older than the current date
  if (sortDate > new Date()) {
    // Change the display style of the original item element to "none"
    item.style.display = "none";
  }
}
```

